#include <iostream>
#include <string>

struct Node {
  int data;
  Node* parent;
  Node* left;
  Node* right;
  Node(int val = 0, Node* p = nullptr) : data(val), parent(p), left(nullptr), right(nullptr) {}
};

struct StackNode {
  Node* node_of_bst;
  StackNode* next;
  StackNode(Node* root) : node_of_bst(root), next(nullptr) {}
};

struct Stack {
  StackNode* head;

  Stack() : head(nullptr) {}

  ~Stack() {
    while (!empty()) pop();
  }

  bool empty() const {
    return head == nullptr;
  }

  void push(Node* root) {
    StackNode* new_node = new StackNode(root);
    new_node->next = head;
    head = new_node;
  }

  Node* top() {
    return empty() ? nullptr : head->node_of_bst;
  }

  void pop() {
    if (!empty()) {
      StackNode* temp = head;
      head = head->next;
      delete temp;
    }
  }
};

int SumCount(Node* root, int64_t& ans) {
  if (!root) return 0;

  int leftSum = root->left ? SumCount(root->left, ans) : 0;
  int rightSum = root->right ? SumCount(root->right, ans) : 0;

  if ((root->left == nullptr || (root->left->data < root->data && leftSum != INT_MIN)) &&
      (root->right == nullptr || (root->right->data > root->data && rightSum != INT_MIN))) {
    int64_t totalSum = root->data + leftSum + rightSum;
    ans = std::max(ans, totalSum);
    return totalSum;
  }
  return INT_MIN;
}

void DeleteTree(Node* root) {
    if (root) {
        DeleteTree(root->left);
        DeleteTree(root->right);
        delete root;
    }
}

int main() {
  Stack stack;
  std::string cmd;
  Node* root = nullptr;
  Node* current = nullptr;

  while (std::cin >> cmd) {
    if (cmd == "l" || cmd == "r") {
      if (!stack.empty() && (cmd == "l" ? current->left : current->right) == nullptr) {
        current = (cmd == "l" ? current->left : current->right) = new Node(0, current);
        stack.push(current);
      }
      continue;
    } else if (cmd == "u") {
      if (!stack.empty()) {
      stack.pop();
      current = stack.empty() ? nullptr : stack.top();    
      }
      continue;
    } else if (isdigit(cmd[0]) || (cmd[0] == '-' && isdigit(cmd[1]))) {
      int data = std::stoi(cmd);
      if (!stack.empty()) {
        current->data = data;
      } else {
        root = current = new Node(data);
        stack.push(current);
      }
      continue;
    }
  }

  int64_t ans = 0;
  SumCount(root, ans);
  std::cout << ans;

  DeleteTree(root);
  return 0;
}


