{
	struct node* root = newNode(4);
	root->left = newNode(2);
	root->right = newNode(5);
	// root->right->left = newNode(7);
	root->left->left = newNode(1);
	root->left->right = newNode(3);

	// Function call
	if (isBST(root))
		printf("Is BST");
	else
		printf("Not a BST");

	return 0;
}
