Node* insertNode(Node* root, string direction, int value) {
	if (root == nullptr) {
		root = new Node(value);
	} else if (direction == "l") {
		root->left = insertNode(root->left, "", value);
	} else if (direction == "r") {
		root->right = insertNode(root->right, "", value);
	}
	return root;
