	if (node->left != nullptr && maxValue(node->left) >= node->data) {
		return false;
	}
	if (node->right != nullptr && minValue(node->right) < node->data) {
		return false;
	}
	return isBST(node->left) && isBST(node->right);
}

int sumBST(Node* node, int& maxSum) {
	if (node == nullptr) {
		return 0;
	}

	if (isBST(node)) {
		int sum = node->data + sumBST(node->left, maxSum) + sumBST(node->right, maxSum);
		maxSum = max(maxSum, sum);
		return sum;
	}

	return 0;
}

int findMaxSumBST(Node* root) {
	int maxSum = 0;
	sumBST(root, maxSum);
	return maxSum;
}

// Helper function to delete tree
void deleteTree(Node* node) {
	if (node) {
		deleteTree(node->left);
		deleteTree(node->right);
		delete node;
