```cpp
// Структура для возвращения нескольких значений из функции
struct SubtreeData {
  bool isBST;
  int sum;
  int min;
  int max;
};

SubtreeData TaskOptimized(Node* root, int64_t& max_sum) {
  if (!root)
    return {true, 0, INT_MAX, INT_MIN}; 

  SubtreeData left = TaskOptimized(root->left, max_sum);
  SubtreeData right = TaskOptimized(root->right, max_sum);

  if (left.isBST && right.isBST && root->data > left.max && root->data < right.min) {
    // Это BST
    int sum = root->data + left.sum + right.sum;
    max_sum = std::max(max_sum, static_cast<int64_t>(sum));
    return {true, sum, std::min(root->data, left.min), std::max(root->data, right.max)};
  } else {
    // Это не BST
    return {false, 0, INT_MIN, INT_MAX};
  }
}

// Вызов функции в main
SubtreeData result = TaskOptimized(root, max_sum);
