#include <iostream>
#include <string>

struct Node {
  int data;
  Node* parent;
  Node* left;
  Node* right;
  Node(int val = 0, Node* p = nullptr) : data(val), parent(p), left(nullptr), right(nullptr) {}
};

struct StackNode {
  Node* node_of_bst;
  StackNode* next;
  StackNode(Node* root) : node_of_bst(root), next(nullptr) {}
};

struct Stack {
  StackNode* head;

  Stack() : head(nullptr) {}

  ~Stack() {
    while (!empty()) pop();
  }

  bool empty() const {
    return head == nullptr;
  }

  void push(Node* root) {
    StackNode* new_node = new StackNode(root);
    new_node->next = head;
    head = new_node;
  }

  Node* top() {
    return empty() ? nullptr : head->node_of_bst;
  }

  void pop() {
    if (!empty()) {
      StackNode* temp = head;
      head = head->next;
      delete temp;
    }
  }
};

bool isBST(Node* node, int min, int max) {
  if (node == nullptr) return true;

  if (node->data <= min || node->data >= max) return false;

  return isBST(node->left, min, node->data) && isBST(node->right, node->data, max);
}

int Task(Node* root, int64_t& max_sum) {
  if (root == nullptr) 
    return 0;

  int sum = root->data;
  int l = Task(root->left, max_sum);
  int r = Task(root->right, max_sum);

  if (isBST(root, INT_MIN, INT_MAX) && l != INT_MIN && r != INT_MIN) {
    sum += l + r;
    max_sum = std::max(max_sum, (int64_t)sum);
    return sum;
  }

  return INT_MIN;
}

void DeleteTree(Node* root) {
  if (root) {
    DeleteTree(root->left);
    DeleteTree(root->right);
    delete root;
  }
}

int main() {
  Stack stack;
  std::string cmd;
  Node* root = nullptr;
  Node* current = nullptr;

  while (std::cin >> cmd) {
    if (cmd == "l" || cmd == "r") {
      if (!stack.empty() && (cmd == "l" ? current->left : current->right) == nullptr) {
        current = (cmd == "l" ? current->left : current->right) = new Node(0, current);
        stack.push(current);
      }
      continue;
    } else if (cmd == "u") {
      if (!stack.empty()) {
      stack.pop();
      current = stack.empty() ? nullptr : stack.top();    
      }
      continue;
    } else if (isdigit(cmd[0]) || (cmd[0] == '-' && isdigit(cmd[1]))) {
      int data = std::stoi(cmd);
      if (!stack.empty()) {
        current->data = data;
      } else {
        root = current = new Node(data);
        stack.push(current);
      }
      continue;
    }
  }

  int64_t max_sum = 0;
  Task(root, max_sum);
  std::cout << max_sum << std::endl;

  DeleteTree(root);
  return 0;
}


