        return {true, 0, std::numeric_limits<int>::max(), std::numeric_limits<int>::min()};
    }

    BSTData left_data = TaskOptimized(node->left, max_sum);
    BSTData right_data = TaskOptimized(node->right, max_sum);
    BSTData current_data;

    if (left_data.is_bst && right_data.is_bst &&
        (node->left == nullptr || node->data > left_data.max_value) &&
        (node->right == nullptr || node->data < right_data.min_value)) {

        // Узел вместе с потомками образует BST.
        current_data.is_bst = true;
        current_data.sum = node->data + left_data.sum + right_data.sum;
        current_data.min_value = (node->left != nullptr) ? left_data.min_value : node->data;
        current_data.max_value = (node->right != nullptr) ? right_data.max_value : node->data;

        // Обновляем максимальную сумму, если нашли большую.
        max_sum = std::max(max_sum, current_data.sum);
    } else {
        // Если нет, то это не BST.
        current_data.is_bst = false;
        current_data.sum = 0; // Сумма для не-BST не имеет значения.
        current_data.min_value = std::numeric_limits<int>::max(); // Minimum не имеет значения.
        current_data.max_value = std::numeric_limits<int>::min(); // Maximum не имеет значения.
    }

    return current_data;
}

