#include <iostream>
#include <vector>
#include <string>

class BST {
private:
    struct Node {
        int id;
        Node* left;
        Node* right;

        Node(int _id) : id(_id), left(nullptr), right(nullptr) {}
    };

    Node* root;

    // Вспомогательная функция для рекурсивного добавления узла в BST
    Node* insert(Node* node, int id) {
        if (node == nullptr) {
            return new Node(id);
        }
        if (id < node->id) {
            node->left = insert(node->left, id);
        } else if (id > node->id) {
            node->right = insert(node->right, id);
        }
        return node;
    }

    // Вспомогательная функция для рекурсивного удаления узла из BST
    Node* remove(Node* node, int id) {
        if (node == nullptr) {
            return nullptr;
        }
        if (id < node->id) {
            node->left = remove(node->left, id);
        } else if (id > node->id) {
            node->right = remove(node->right, id);
        } else {
            if (node->left == nullptr) {
                Node* temp = node->right;
                delete node;
                return temp;
            } else if (node->right == nullptr) {
                Node* temp = node->left;
                delete node;
                return temp;
            }
            Node* temp = findMin(node->right);
            node->id = temp->id;
            node->right = remove(node->right, temp->id);
        }
        return node;
    }

    // Нахождение минимального идентификатора узла в поддереве
    Node* findMin(Node* node) {
        Node* current = node;
        while (current && current->left != nullptr) {
            current = current->left;
        }
        return current;
    }

    // Вспомогательная функция для инордерного обхода дерева
    void inorder(Node* node) {
        if (node == nullptr) {
            return;
        }
        inorder(node->left);
        std::cout << node->id << " ";
        inorder(node->right);
    }

    // Удаление и очищение всех узлов дерева
    void clear(Node*& node) {
        if (node == nullptr) {
            return;
        }
        clear(node->left);
        clear(node->right);
        delete node;
        node = nullptr;
    }

    // Вспомогательная функция для слияния двух BST
    void merge(Node*& node1, Node* node2) {
        if (node2 == nullptr) return;
        insert(node1, node2->id);
        merge(node1, node2->left);
        merge(node1, node2->right);
    }

public:
    // Конструктор
    BST() : root(nullptr) {}

    // Деструктор
    ~BST() {
        clear(root);
    }

    // Операция покупки (бай)
    void buy(int id) {
        root = insert(root, id);
    }

    // Операция продажи (селл)
    void sell(int id) {
        root = remove(root, id);
    }

    // Операция слияния (мерж)
    void merge(BST& secondary) {
        merge(root, secondary.root);
        secondary.clear(secondary.root);
    }

    // Отображение акций в инордерном порядке
    void show() {
        inorder(root);
        std::cout << "\n";
    }
};

